queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?technique_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:technique_id ?cg . ?child a :Techniques ; p:id ?cg . ?l p:data_analyst_id ?pg . ?parent a :Data_Analysts ; p:id ?pg . } GROUP BY ?child }
  ?child p:technique_name ?technique_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Data_Analysts } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?technique_name WHERE {
  ?data_analysts_techniques a :Data_Analysts_Techniques .
  ?techniques a :Techniques .
  ?data_analysts_techniques p:hasTechniques ?techniques .
  ?data_analysts a :Data_Analysts .
  ?data_analysts_techniques p:hasData_Analysts ?data_analysts .
  ?data_analysts p:name ?name .
  ?techniques p:technique_name ?technique_name .
} }
  collective: { SELECT ?technique_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:technique_id ?cg . ?child a :Techniques ; p:id ?cg . ?l p:data_analyst_id ?pg . ?parent a :Data_Analysts ; p:id ?pg . } GROUP BY ?child }
  ?child p:technique_name ?technique_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Data_Analysts } }
  FILTER(?nf = ?total)
} }
}
